const safeItems = (nodeName) => {
  try {
    return $items(nodeName) || [];
  } catch (e) {
    return [];
  }
};

const caseCtx = $node["Get Case Details"]?.json ?? {};
const resolvedCtx = safeItems("Resolve Preference")[0]?.json ?? {};
const transcriptCtx = $node["Fetch Transcript"]?.json ?? {};

const oms = safeItems("Query OMS")[0]?.json ?? {};
const paymentTxnItems = safeItems("Query Payment - Txn");
const refundsItems = safeItems("Query Payment - Refunds");
const logisticsItems = safeItems("Query Logistics");
const inventoryItems = safeItems("Query Inventory");

const transaction = paymentTxnItems[0]?.json?.transaction ?? null;
const refund_records = refundsItems[0]?.json?.refund_records ?? [];
const shipment = logisticsItems[0]?.json?.shipment ?? null;
const tracking_events = logisticsItems[0]?.json?.tracking_events ?? [];
const stock_records = inventoryItems[0]?.json?.stock_records ?? [];

const order = oms.order ?? null;
const order_items = Array.isArray(oms.order_items) ? oms.order_items : [];

const resolved_case_id =
  resolvedCtx.resolved_case_id ??
  caseCtx.id ??
  null;

const resolved_order_id =
  resolvedCtx.resolved_order_id ??
  caseCtx.order_id ??
  order?.order_id ??
  null;

const resolved_dispute_type =
  resolvedCtx.resolved_dispute_type ??
  caseCtx.dispute_type ??
  null;

const resolved_dispute_subtype =
  resolvedCtx.resolved_dispute_subtype ??
  caseCtx.dispute_subtype ??
  null;

const resolved_resolution_preference =
  resolvedCtx.resolved_resolution_preference ??
  caseCtx.resolution_preference ??
  null;

const proof_requirements =
  resolvedCtx.resolved_proof_requirements ??
  caseCtx.proof_requirements ??
  null;

const proof_uploads =
  resolvedCtx.resolved_proof_uploads ??
  caseCtx.proof_uploads ??
  [];

const proof_analysis =
  resolvedCtx.resolved_proof_analysis ??
  caseCtx.proof_analysis ??
  null;

const proof_analysis_status =
  resolvedCtx.resolved_proof_analysis_status ??
  caseCtx.proof_analysis_status ??
  null;

const case_evidence_bundle =
  resolvedCtx.resolved_evidence_bundle ??
  caseCtx.evidence_bundle ??
  null;

const invalid_reason_code = caseCtx.invalid_reason_code ?? null;
const invalid_reason_detail = caseCtx.invalid_reason_detail ?? null;
const appeal_priority = caseCtx.appeal_priority ?? null;

const normalize = (value) => String(value ?? "").trim().toLowerCase();
const toArray = (value) => (Array.isArray(value) ? value : []);

const uniqueStrings = (values) => {
  const seen = new Set();

  return values.filter((value) => {
    const normalized = String(value ?? "").trim();
    if (!normalized || seen.has(normalized)) return false;
    seen.add(normalized);
    return true;
  });
};

const nameVariants = (value) => {
  const text = String(value ?? "").trim();
  if (!text) return [];

  const lowered = text.toLowerCase();

  return uniqueStrings([
    lowered,
    lowered.replace(/-/g, " "),
    lowered.replace(/[()]/g, ""),
    lowered.replace(/-/g, " ").replace(/[()]/g, ""),
  ]);
};

const extractMessageArrays = (ctx) => {
  const candidates = [
    ctx?.messages,
    ctx?.transcript,
    ctx?.chat_messages,
    ctx?.conversation,
    ctx?.history,
    ctx?.message_history,
  ];

  const arrays = candidates.filter(Array.isArray);
  return arrays.flat();
};

const transcript_messages = extractMessageArrays(transcriptCtx);

const sanitizeMessage = (message) => ({
  id: message?.id ?? null,
  sender_type: message?.sender_type ?? null,
  content: message?.content ?? null,
  created_at: message?.created_at ?? null,
  metadata: message?.metadata ?? message?.metadata_ ?? null,
});

const matchItemIdsFromText = (messages, orderItems) => {
  const orderedMessages = [...messages].reverse();

  for (const message of orderedMessages) {
    if (normalize(message?.sender_type) !== "customer") continue;

    const content = normalize(message?.content);
    if (!content) continue;

    const matched = [];

    for (const item of orderItems) {
      const itemId = item?.item_id ?? null;
      const itemName = item?.item_name ?? item?.product_name ?? null;
      const variants = [
        ...nameVariants(itemName),
        ...nameVariants(itemId),
      ];

      if (variants.some((variant) => variant && content.includes(variant))) {
        if (itemId) matched.push(itemId);
      }
    }

    if (matched.length > 0) {
      return uniqueStrings(matched);
    }
  }

  return [];
};

const extractAffectedItemIds = (contexts, orderItems) => {
  for (const ctx of contexts) {
    const directIds = toArray(ctx?.affected_item_ids)
      .map((value) => String(value ?? "").trim())
      .filter(Boolean);

    if (directIds.length > 0) {
      return uniqueStrings(directIds);
    }

    const directItems = toArray(ctx?.affected_items)
      .map((item) => item?.item_id ?? item?.sku ?? null)
      .filter(Boolean)
      .map((value) => String(value).trim());

    if (directItems.length > 0) {
      return uniqueStrings(directItems);
    }

    const messages = extractMessageArrays(ctx);

    if (messages.length > 0) {
      for (const message of [...messages].reverse()) {
        if (normalize(message?.sender_type) !== "customer") continue;

        const metadata = message?.metadata ?? message?.metadata_ ?? null;
        if (!metadata || typeof metadata !== "object") continue;

        if (normalize(metadata.selection_type) === "affected_items") {
          const rawIds = toArray(metadata.affected_item_ids)
            .map((value) => String(value ?? "").trim())
            .filter(Boolean);

          if (rawIds.length > 0) {
            return uniqueStrings(rawIds);
          }
        }
      }

      const matchedFromText = matchItemIdsFromText(messages, orderItems);
      if (matchedFromText.length > 0) {
        return matchedFromText;
      }
    }
  }

  return [];
};

const proof_messages = transcript_messages
  .filter((message) => {
    const metadata = message?.metadata ?? message?.metadata_ ?? null;
    if (!metadata || typeof metadata !== "object") return false;

    return (
      normalize(metadata.role) === "proof_upload" ||
      normalize(metadata.role) === "proof_request" ||
      normalize(metadata.action) === "proof_uploaded"
    );
  })
  .map(sanitizeMessage);

const proof_attachments = proof_messages.flatMap((message) => {
  const metadata = message?.metadata;
  if (!metadata || typeof metadata !== "object") return [];
  return Array.isArray(metadata.attachments) ? metadata.attachments : [];
});

const intake_messages = transcript_messages
  .filter((message) => {
    const metadata = message?.metadata ?? message?.metadata_ ?? null;
    if (!metadata || typeof metadata !== "object") return false;

    return (
      normalize(metadata.role) === "intake_question" ||
      normalize(metadata.role) === "proof_request" ||
      normalize(metadata.role) === "intake_insufficient_context"
    );
  })
  .map(sanitizeMessage);

const recent_transcript = transcript_messages
  .slice(-20)
  .map(sanitizeMessage);

const stockMap = {};
stock_records.forEach((stock) => {
  if (stock?.item_id) {
    stockMap[stock.item_id] = stock;
  }
});

const order_items_detail = order_items.map((item) => {
  const stock = stockMap[item.item_id] || {};

  return {
    order_id: item.order_id ?? resolved_order_id ?? null,
    item_id: item.item_id ?? null,
    product_name: item.item_name ?? item.product_name ?? null,
    quantity_ordered: item.quantity ?? null,
    unit_price: item.unit_price ?? null,
    quantity_available_now: stock.quantity_available ?? null,
    warehouse_location: stock.warehouse_location ?? null,
    sku: item.item_id ?? null,
  };
});

const affected_item_ids = extractAffectedItemIds(
  [resolvedCtx, caseCtx, transcriptCtx],
  order_items
);

const normalizedAffectedIds = new Set(
  affected_item_ids.map((value) => normalize(value)).filter(Boolean)
);

const affected_items_detail =
  normalizedAffectedIds.size > 0
    ? order_items_detail.filter((item) => {
        const itemId = normalize(item.item_id);
        const sku = normalize(item.sku);
        return normalizedAffectedIds.has(itemId) || normalizedAffectedIds.has(sku);
      })
    : [];

const payment_records = [];

if (transaction) {
  payment_records.push({
    transaction_id: transaction.transaction_id ?? transaction.id ?? null,
    order_id: transaction.order_id ?? resolved_order_id ?? null,
    transaction_type: "payment",
    amount: transaction.amount ?? null,
    status: transaction.status ?? null,
    payment_method: transaction.payment_method ?? null,
    transaction_date: transaction.transaction_date ?? transaction.transacted_at ?? null,
  });
}

if (Array.isArray(refund_records)) {
  refund_records.forEach((refund) => {
    payment_records.push({
      transaction_id: refund.refund_id ?? refund.id ?? null,
      order_id: refund.order_id ?? resolved_order_id ?? null,
      transaction_type: "refund",
      amount: refund.refund_amount ?? refund.amount ?? null,
      status: refund.status ?? null,
      payment_method: refund.refund_method ?? null,
      transaction_date: refund.refund_date ?? null,
    });
  });
}

const delivered_at =
  shipment?.delivered_at ??
  order?.fulfilled_at ??
  order?.delivered_at ??
  null;

const fulfilled_at =
  order?.fulfilled_at ??
  order?.delivered_at ??
  null;

const fallback_evidence_bundle = {
  proof_present: Array.isArray(proof_uploads) && proof_uploads.length > 0,
  proof_upload_count: Array.isArray(proof_uploads) ? proof_uploads.length : 0,
  proof_uploads,
  proof_analysis_status,
  proof_analysis,
  invalid_reason_code,
  invalid_reason_detail,
};

const bundle = {
  // Legacy keys
  order,
  order_items,
  transaction,
  refund_records,
  shipment,
  tracking_events,
  stock_records,

  // Canonical normalized data
  order_data: order
    ? {
        order_id: order.order_id ?? resolved_order_id ?? null,
        customer_name: order.customer_name ?? null,
        customer_email: order.customer_email ?? null,
        order_date: order.order_date ?? order.created_at ?? null,
        total_amount: order.total_amount ?? null,
        order_status: order.status ?? order.order_status ?? null,
        fulfilled_at,
        delivered_at,
      }
    : null,

  payment_records,

  shipment_data: shipment
    ? {
        shipment_id: shipment.shipment_id ?? shipment.id ?? null,
        order_id: shipment.order_id ?? resolved_order_id ?? null,
        carrier: shipment.carrier ?? null,
        tracking_number: shipment.tracking_number ?? null,
        status: shipment.status ?? null,
        estimated_delivery: shipment.estimated_delivery ?? null,
        shipped_at: shipment.shipped_at ?? null,
        delivered_at: shipment.delivered_at ?? null,
      }
    : null,

  order_items_detail,

  // Additive affected-item fields
  affected_item_ids,
  affected_items_detail,

  // Proof and evidence layer
  proof_requirements,
  proof_uploads,
  proof_analysis,
  proof_analysis_status,
  evidence_bundle: case_evidence_bundle ?? fallback_evidence_bundle,
  proof_messages,
  proof_attachments,

  // Intake / transcript context
  intake_messages,
  recent_transcript,

  // Case status context
  invalid_reason_code,
  invalid_reason_detail,
  appeal_priority,

  dispute_type: resolved_dispute_type,
  dispute_subtype: resolved_dispute_subtype,
  resolution_preference: resolved_resolution_preference,
  queried_at: new Date().toISOString(),
};

return [
  {
    case_id: resolved_case_id,
    order_id: resolved_order_id,
    dispute_type: resolved_dispute_type,
    dispute_subtype: resolved_dispute_subtype,
    resolution_preference: resolved_resolution_preference,
    information_bundle: bundle,
  },
];

const caseCtx = $node["Get Case Details"].json || {};
const current = $input.first().json || {};

return [{
  ...current,
  resolved_case_id: String(caseCtx.id || "").trim(),
  resolved_order_id: String(caseCtx.order_id || "").trim(),
  resolved_dispute_type: String(caseCtx.dispute_type || "").trim().toLowerCase(),
  resolved_dispute_subtype: String(caseCtx.dispute_subtype || "").trim().toLowerCase(),
  resolved_resolution_preference: String(caseCtx.resolution_preference || "").trim().toLowerCase(),
  resolved_proof_requirements: caseCtx.proof_requirements || null,
  resolved_proof_uploads: caseCtx.proof_uploads || [],
  resolved_evidence_bundle: caseCtx.evidence_bundle || null,
  resolved_proof_analysis: caseCtx.proof_analysis || null,
  resolved_proof_analysis_status: caseCtx.proof_analysis_status || null,
}];
